-- Migration 004: Blog system
-- Creates blog_posts and blog_comments tables with indexes and seed data

BEGIN;

-- Blog posts table
CREATE TABLE IF NOT EXISTS blog_posts (
    id SERIAL PRIMARY KEY,
    author_id INTEGER NOT NULL REFERENCES users(id),
    title VARCHAR(255) NOT NULL,
    slug VARCHAR(120) NOT NULL UNIQUE,
    content TEXT NOT NULL,
    excerpt TEXT,
    cover_image VARCHAR(500),
    language VARCHAR(5) NOT NULL DEFAULT 'en',
    tags TEXT[] DEFAULT '{}',
    is_published BOOLEAN NOT NULL DEFAULT false,
    published_at TIMESTAMP,
    view_count INTEGER NOT NULL DEFAULT 0,
    created_at TIMESTAMP NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMP NOT NULL DEFAULT NOW()
);

-- Blog comments table
CREATE TABLE IF NOT EXISTS blog_comments (
    id SERIAL PRIMARY KEY,
    post_id INTEGER NOT NULL REFERENCES blog_posts(id) ON DELETE CASCADE,
    user_id INTEGER NOT NULL REFERENCES users(id),
    content TEXT NOT NULL,
    parent_id INTEGER REFERENCES blog_comments(id),
    created_at TIMESTAMP NOT NULL DEFAULT NOW()
);

-- Indexes
CREATE INDEX IF NOT EXISTS idx_blog_posts_slug ON blog_posts (slug);
CREATE INDEX IF NOT EXISTS idx_blog_posts_published_at ON blog_posts (published_at DESC) WHERE is_published = true;
CREATE INDEX IF NOT EXISTS idx_blog_posts_tags ON blog_posts USING GIN (tags);
CREATE INDEX IF NOT EXISTS idx_blog_comments_post_id ON blog_comments (post_id);

-- Seed 3 blog posts (author_id=28)
INSERT INTO blog_posts (author_id, title, slug, content, excerpt, language, tags, is_published, published_at)
VALUES
(
    28,
    'Welcome to the Savchenko Solutions Blog',
    'welcome-to-the-savchenko-solutions-blog',
    E'## Why a Blog?\n\nFor over two years, Savchenko Solutions has been a quiet workshop: contributors upload solutions, students find them, and the cycle continues. But behind every solution is a story — a creative trick, a subtle physical insight, or a hard-won lesson about what **not** to do. Those stories never had a home. Until now.\n\nThis blog is the place where we step back from individual problems and talk about the bigger picture: how to study physics effectively, what makes Savchenko''s collection unique, and how a small open-source project grew into a platform used by students in over 150 countries.\n\n## What to Expect\n\nWe plan to publish a mix of content that serves both new visitors and long-time contributors:\n\n**Study guides and strategy.** Which chapters should you tackle first? How do you build the mathematical toolkit that Savchenko assumes you already have? We''ll share concrete roadmaps based on the experience of dozens of contributors who have worked through these problems.\n\n**Deep dives into specific problems.** Some Savchenko problems are famous for being deceptively simple on the surface but requiring real ingenuity. We''ll pick one problem at a time and walk through not just the solution, but the *thinking process* — the false starts, the key insight, and why the answer is physically reasonable.\n\n**Platform updates.** When we ship new features, fix long-standing bugs, or reach milestones, you''ll hear about it here first. We believe in building in public, and this blog is part of that commitment.\n\n**Contributor spotlights.** Savchenko Solutions has 72 contributors from 18 countries. Their backgrounds range from physics olympiad coaches to undergraduates discovering the collection for the first time. We want to tell their stories.\n\n## Who Writes Here?\n\nAnyone with a verified contributor account can write blog posts. That said, we''ll start with a small editorial team to establish the tone and quality bar. If you''re interested in writing, reach out — we''re always looking for people who can explain physics clearly.\n\n## The Bigger Mission\n\nSavchenko''s *Problems in Physics* is one of the most rigorous problem collections in the post-Soviet physics tradition. For decades, it was accessible primarily to Russian-speaking students. Our mission is to make every solution available, peer-reviewed, and free — in both English and Russian.\n\nThe blog is an extension of that mission. Good physics education is not just about having the right answer; it''s about understanding *why* the answer is right, *how* to find it, and *what* it teaches you about the physical world.\n\nWelcome. We''re glad you''re here.\n\n---\n\n*Have a topic you''d like us to cover? Drop a comment below or email us at aliaksandr@melnichenka.com.*',
    'Introducing the Savchenko Solutions blog: study guides, problem deep dives, platform updates, and contributor spotlights.',
    'en',
    ARRAY['announcement', 'meta'],
    true,
    NOW() - INTERVAL '2 days'
),
(
    28,
    'How to Start Solving Savchenko Problems',
    'how-to-start-solving-savchenko-problems',
    E'## The Reputation Problem\n\nSavchenko''s collection has a reputation for being impossibly hard. That reputation is partly deserved — the later chapters on electrodynamics, optics, and relativity contain problems that challenge graduate students. But the early chapters are surprisingly accessible if you approach them with the right preparation and mindset.\n\nThis guide is for students who have heard of Savchenko, are curious, and want a practical plan for getting started.\n\n## Prerequisites\n\nBefore opening the book, make sure you are comfortable with:\n\n- **Kinematics in one and two dimensions.** You should be able to set up coordinate systems, write equations of motion, and solve them. If projectile motion still feels shaky, solidify that first.\n- **Newton''s laws.** Free-body diagrams should be second nature. You should be able to handle systems of two or three connected bodies without hesitation.\n- **Basic calculus.** Many Savchenko problems require differentiation and integration. You don''t need real analysis, but you need to be fluent with derivatives, integrals, and solving simple differential equations like $\\frac{dv}{dt} = -kv$.\n- **Trigonometry and geometry.** Savchenko loves geometric arguments. Comfort with the law of cosines, properties of similar triangles, and basic solid geometry will serve you well.\n\nIf any of these feel weak, spend a few weeks strengthening them before diving in. Savchenko problems reward preparation, not brute force.\n\n## Recommended Order\n\nDo **not** start at problem 1.1.1 and grind forward sequentially. Instead, try this path:\n\n### Phase 1: Build Confidence (Weeks 1-4)\n\nStart with **Chapter 1 (Kinematics)**, sections 1.1 through 1.3. These problems range from straightforward to moderately tricky, and they build essential skills in setting up reference frames and analyzing motion.\n\nThen jump to **Chapter 2 (Dynamics)**, sections 2.1 through 2.3. Newton''s second law problems in Savchenko are excellent because they force you to be precise about which forces act on which body.\n\nAim for 3-5 problems per day. Quality matters more than quantity.\n\n### Phase 2: Expand Your Toolkit (Weeks 5-10)\n\nNow tackle **Chapter 3 (Energy and Momentum)**. Energy conservation and momentum conservation are the workhorses of physics problem-solving, and Savchenko''s problems in this chapter will stretch your ability to choose the right conservation law.\n\nAdd **Chapter 5 (Thermodynamics)**, sections 5.1 through 5.3. Ideal gas problems are a natural next step and introduce you to Savchenko''s style in a different domain.\n\n### Phase 3: The Hard Stuff (Weeks 11+)\n\nWith a solid foundation, you can branch into:\n- **Chapter 4 (Rotation)** — angular momentum and torque problems\n- **Chapter 6 (Electrostatics)** — Savchenko''s electrostatics problems are legendary\n- **Chapter 7 (Electric Current)** — circuit analysis with a physics twist\n\nLeave Chapters 11-14 (Electrodynamics, Optics, Relativity, Quantum) until you have significant experience.\n\n## How to Work a Problem\n\n1. **Read the problem twice.** The first time for the story, the second time for the data.\n2. **Draw a diagram.** Even if it seems unnecessary. Savchenko problems often have geometric subtleties that only become visible when drawn.\n3. **Identify the physics.** What conservation laws apply? What constraints exist? Which quantities are given and which are unknowns?\n4. **Set up equations before plugging in numbers.** Work symbolically as long as possible. Symbolic answers are easier to check dimensionally and reveal physical dependencies.\n5. **Check your answer.** Does it have the right dimensions? Does it behave correctly in limiting cases? If $m \\to 0$ or $v \\to 0$, does the answer make physical sense?\n\n## When You Get Stuck\n\nGetting stuck is normal. Savchenko''s problems are *designed* to require creative thinking. Here is what to do:\n\n- **Step away for 15 minutes.** Seriously. Your subconscious will keep working.\n- **Try a different approach.** If energy conservation isn''t working, try force analysis. If Cartesian coordinates are messy, try polar.\n- **Look at the solution, but actively.** When you check our solutions on SavchenkoSolutions.com, don''t just read them passively. Find the key step you were missing, close the solution, and finish the problem yourself.\n- **Come back to hard problems later.** Mark problems you couldn''t solve and revisit them after a week. You''ll be surprised how often the answer becomes obvious after more experience.\n\n## The Long Game\n\nSavchenko is a marathon, not a sprint. The students who benefit most are the ones who work consistently over months, building a deep and flexible understanding of physics. There are 2,023 problems in the collection. Nobody expects you to solve all of them. Even solving 200-300 from a well-chosen selection will transform your physics ability.\n\nGood luck. And when you solve a problem that doesn''t have a solution on our site yet, consider uploading yours. That''s how this community grows.\n\n---\n\n*Questions about where to start? Leave a comment and we''ll help you build a personalized plan.*',
    'A practical guide to tackling the Savchenko problem collection: prerequisites, recommended chapter order, problem-solving workflow, and what to do when you get stuck.',
    'en',
    ARRAY['guide', 'study-tips', 'beginners'],
    true,
    NOW() - INTERVAL '1 day'
),
(
    28,
    'The Story Behind Savchenko Solutions',
    'the-story-behind-savchenko-solutions',
    E'## One Student, One Problem at a Time\n\nSavchenko Solutions started in late 2023 as a personal project. I was working through Savchenko''s *Problems in Physics* and found that good solutions were scattered across obscure forums, handwritten PDFs of varying quality, and Russian-language sites that were difficult for international students to access. There was no single, reliable, open-access resource.\n\nSo I started building one. The first version was a static GitHub Pages site — plain HTML files, one per problem, with hand-written LaTeX solutions rendered by MathJax. No database, no user accounts, no interactivity. Just solutions.\n\nThe first month had maybe 50 visitors. Most of them were probably me, refreshing the page to check if MathJax was rendering correctly.\n\n## The Migration to a Real Platform\n\nBy mid-2024, the static site had grown to several hundred solutions, and its limitations were obvious. Editing a solution meant committing HTML to a Git repository. There was no way for other people to contribute without knowing Git. The site had no search, no way to track which problems were solved, and no mechanism for quality control.\n\nIn late 2024, I rebuilt the entire platform as a server-side rendered Express.js application with a PostgreSQL database. Solutions were migrated from raw HTML to Markdown. User accounts, contribution tracking, and an editing interface were added. The 11,493 edits from the GitHub Pages era were preserved in a separate `github_contributions` table so that contributor history was never lost.\n\nThis migration was the inflection point. Within weeks, contributors who had been sending me corrections via email could now edit solutions directly.\n\n## Growth by the Numbers\n\nThe numbers tell the story of a community that grew organically, almost entirely through word of mouth:\n\n- **1,516 solutions** are now published across English and Russian\n- **72 contributors** from **18 countries** have made edits\n- **710 registered users** have created accounts\n- **150,000+ unique visitors** from **150+ countries** have used the site\n- **6,311 edits** have been made since the platform migration\n- **17,804 total edits** including the GitHub Pages era\n\nThe largest contributor communities are in Russia, the United States, Georgia, Belarus, and Kazakhstan — a mix that reflects both the book''s post-Soviet origins and its growing international audience.\n\n## The LEX 18 Feature\n\nIn early 2025, the local news station LEX 18 in Lexington, Kentucky ran a segment about the project. It was surreal — a physics problem-solving website being discussed on evening news alongside weather reports and high school sports. But the story resonated: a student-built platform making elite physics education freely accessible.\n\nThe traffic spike from that segment introduced us to a new audience of American physics teachers and students who had never heard of Savchenko but were immediately drawn to the rigor and depth of the problems.\n\n## How Contributors Work\n\nEvery solution on the site goes through a simple but effective workflow:\n\n1. A contributor writes or edits a solution using our Markdown editor with live MathJax preview.\n2. The edit is saved and immediately visible (we trust our contributors, and every edit is versioned).\n3. Other contributors can review, correct, and improve the solution over time.\n4. Comments allow discussion about alternative approaches or errors.\n\nThis model is deliberately simple. We don''t have a formal peer review process with approvals and rejections — that would slow things down and discourage contributions. Instead, we rely on the fact that physics is self-correcting: if a solution has an error, someone will eventually notice and fix it. Our contribution history preserves every version, so nothing is ever lost.\n\n## What We''ve Learned\n\n**Simplicity scales.** The platform has no build step, no SPA framework, no complex deployment pipeline. It''s a Node.js server rendering EJS templates, talking to a PostgreSQL database. This simplicity makes it easy for new contributors to understand the codebase and submit improvements.\n\n**Trust your contributors.** Opening up editing without approval gates felt risky, but it was the right call. The vast majority of edits are genuine improvements. The few bad edits are quickly caught and reverted.\n\n**Content is king.** No amount of UI polish matters if the solutions are wrong or hard to follow. We spend most of our effort on solution quality, not features.\n\n**The long tail matters.** The most-viewed problems are in the early chapters, but the solutions that generate the most grateful feedback are often for obscure problems in later chapters — the ones that students simply cannot find help for anywhere else.\n\n## What''s Next\n\nWe''re not done. Here is what we are working on:\n\n- **Complete coverage.** 507 problems still have no solution. Closing that gap is our primary mission.\n- **Quality improvements.** Many early solutions are terse and could benefit from more explanation, better diagrams, and alternative approaches.\n- **Platform features.** Better search, solution bookmarking, and this blog are recent additions. We have more planned.\n- **Community growth.** We want to reach physics students in countries and languages beyond English and Russian.\n\nEvery solution uploaded, every error corrected, and every comment posted makes this resource better for the next student who needs it. That''s the engine that drives Savchenko Solutions, and it''s powered entirely by volunteers who believe that good physics education should be free.\n\n---\n\n*Want to contribute? Create an account and start editing. Every correction counts.*',
    'From a static GitHub Pages site to a platform with 72 contributors from 18 countries: how Savchenko Solutions grew and where it is headed.',
    'en',
    ARRAY['history', 'community', 'announcement'],
    true,
    NOW()
);

COMMIT;
